import { By } from "selenium-webdriver";
import ojwd, { DriverLike, register } from "../../";
import { OjMenuButton } from "./OjMenuButton";
export { OjMenuButton };

/**
 * Create an instance of [[OjMenuButton]].  This function will first wait for
 * the element to appear in the DOM before trying to locate it.
 * @example
 * <code>
 * const el = await ojMenuButton(driver, By.id('my-oj-menu-button'))
 * </code>
 * @param driver A WebDriver/WebElement instance used to locate the component
 * element.
 * @param by The By locator with which to find the element
 */
export async function ojMenuButton(driver: DriverLike, by: By): Promise<OjMenuButton> {
  const webEl = await driver.findElement(by);
  // Check that the element is of type OjMenuButton
  if (!(webEl instanceof OjMenuButton)) {
    const tagName = await webEl.getTagName();
    throw Error(`Locator '${by}' located a <${tagName}>, but expected <oj-menu-button>`);
  }
  return webEl;
}

register("oj-menu-button", OjMenuButton);
